import { HStack, Text } from '@legos/primitives';
import { Draft3Icon, WhatsupIcon, BlueEmailIcon, ApiIcon } from '@legos/icons';
import { OrderFunnel } from '@dove/graphql/graphql';

interface Props {
  funnel: OrderFunnel;
}

const funnelIconMap: Record<OrderFunnel, React.ElementType> = {
  [OrderFunnel.Draft]: Draft3Icon,
  [OrderFunnel.Whatsup]: WhatsupIcon,
  [OrderFunnel.Email]: BlueEmailIcon,
  [OrderFunnel.Api]: ApiIcon,
  [OrderFunnel.Root]: Draft3Icon,
};

export const DraftOrderFunnelTag = ({ funnel }: Props) => {
  const Icon = funnelIconMap[funnel];
  return (
    <HStack>
      <Icon />
      <Text capitalize>{funnel}</Text>
    </HStack>
  );
};

